import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as d,c as o,e as c}from"./app-be253e4c.js";const r={},t=c(`<h1 id="mvp模式" tabindex="-1"><a class="header-anchor" href="#mvp模式" aria-hidden="true">#</a> MVP模式</h1><p><code>MVC</code>即模型<code>Model</code>、视图<code>View</code>、管理器<code>Presenter</code>，<code>MVP</code>模式从<code>MVC</code> 模式演变而来，通过管理器将视图与模型巧妙地分开，即将<code>Controller</code>改名为<code>Presenter</code>，同时改变了通信方向，<code>MVP</code> 模式模式不属于一般定义的<code>23</code>种设计模式的范畴，而通常将其看作广义上的架构型设计模式。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>在<code>MVC</code>里<code>View</code>是可以直接访问<code>Model</code>中数据的，但<code>MVP</code>中的<code>View</code>并不能直接使用<code>Model</code>，而是通过为<code>Presenter</code> 提供接口，让<code>Presenter</code>去更新<code>Model</code>，再通过观察者模式等方式更新<code>View</code>，与<code>MVC</code>相比，<code>MVP</code>模式通过解耦<code>View</code>和<code>Model</code> ，完全分离视图和模型使职责划分更加清晰，由于<code>View</code>不依赖<code>Model</code>，可以将<code>View</code>抽离出来做成组件，其只需要提供一系列接口提供给上层操作。</p><div class="language-text" data-ext="text"><pre class="language-text"><code>View &lt;-&gt; Controller &lt;-&gt; Model
</code></pre></div><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2><p>在这里我们主要是示例<code>MVP</code>的分层结构，如果要实现<code>MVP</code>信息传递就需要进行一些指令与事件的解析等，<code>Presenter</code>作为<code>View</code> 和<code>Model</code>之间的中间人，除了基本的业务逻辑外，还需要实现对从<code>View</code>到<code>Model</code>以及从<code>Model</code>到<code>View</code> 的数据进行手动同步，例如我们在<code>View</code>中实现一个<code>++</code>计数器就需要在<code>Presenter</code>实现具体操作的<code>Model</code>进行<code>++</code>后再<code>Render</code> 到视图中，此外由于没有数据绑定，如果<code>Presenter</code> 对视图渲染的需求增多，其不得不过多关注特定的视图，一旦视图需求发生改变<code>Presenter</code>也需要改动。</p>`,7),a=[t];function n(i,l){return d(),o("div",null,a)}const h=e(r,[["render",n],["__file","mvp-mode.html.vue"]]);export{h as default};
